40	//
41	// copy_if -- Predicated Copy
42	//
43	
44	template <class PrdTensor,
45	          class SrcEngine, class SrcLayout,
46	          class DstEngine, class DstLayout>
47	CUTE_HOST_DEVICE
48	void
49	copy_if(PrdTensor                    const& pred,
50	        Tensor<SrcEngine, SrcLayout> const& src,
51	        Tensor<DstEngine, DstLayout>      & dst)
52	{
53	  using SrcType = typename SrcEngine::value_type;
54	  using DstType = typename DstEngine::value_type;
55	
56	  CUTE_UNROLL
57	  for (int i = 0; i < size(dst); ++i) {
58	    if (pred(i)) {
59	      dst(i) = static_cast<DstType>(static_cast<SrcType>(src(i)));
60	    }
61	  }
62	}
63	
64	//
65	// copy_if -- Predicated CopyAtom
66	//
67	
68	// Predicate Tensor is an Actual Tensor
69	template <class... CopyArgs,
70	          class PrdEngine, class PrdLayout,
71	          class SrcEngine, class SrcLayout,
72	          class DstEngine, class DstLayout>
73	CUTE_HOST_DEVICE
74	void
75	copy_if(Copy_Atom<CopyArgs...>       const& copy_atom,
76	        Tensor<PrdEngine, PrdLayout> const& prd,       // ([V],Rest...)
77	        Tensor<SrcEngine, SrcLayout> const& src,       // ( V, Rest...)
78	        Tensor<DstEngine, DstLayout>      & dst)       // ( V, Rest...)
79	{
80	  if constexpr (PrdLayout::rank == SrcLayout::rank - 1) {
81	    // Back-compat ONLY -- Delete?
82	    copy_if(copy_atom, make_tensor(prd.data(), prepend(prd.layout(), Layout<_1,_0>{})), src, dst);
83	  } else {
84	    static_assert(SrcLayout::rank == DstLayout::rank, "CopyAtom rank-mismatch.");
85	    static_assert(SrcLayout::rank == PrdLayout::rank, "CopyAtom rank-mismatch.");
86	
87	    if constexpr (SrcLayout::rank == 1) {   // Dispatch the copy
88	      copy_atom.call(prd, src, dst);
89	    } else {                                // Loop over all but the first mode
90	      constexpr int R = SrcLayout::rank;
91	      Tensor prd_v = group_modes<1,R>(prd);
92	      Tensor src_v = group_modes<1,R>(src);
93	      Tensor dst_v = group_modes<1,R>(dst);
94	      CUTE_UNROLL
95	      for (int i = 0; i < size<1>(dst_v); ++i) {
96	        copy_atom.call(prd_v(_,i), src_v(_,i), dst_v(_,i));
97	      }
98	    }
99	  }
100	}
101	
102	template <class... CopyArgs,
103	          class PredTensor,
104	          class SrcEngine, class SrcLayout,
105	          class DstEngine, class DstLayout>
106	[[deprecated("Use a bool-tensor or transform-tensor as predication.")]]
107	CUTE_HOST_DEVICE
108	void
109	copy_if(Copy_Atom<CopyArgs...>       const& copy_atom,
110	        PredTensor                   const& pred,      // (Rest...)
111	        Tensor<SrcEngine, SrcLayout> const& src,       // (V,Rest...)
112	        Tensor<DstEngine, DstLayout>      & dst)       // (V,Rest...)
113	{
114	  Tensor tpred = cute::lazy::transform(make_tensor(counting_iterator<int>{}, replace<0>(shape(dst), _1{})), pred);
115	  return copy_if(copy_atom, tpred, src, dst);
116	}
