118	//
119	// copy_if -- AutoCopyAsync
120	//
121	
122	template <class PrdTensor,
123	          class SrcEngine, class SrcLayout,
124	          class DstEngine, class DstLayout>
125	CUTE_HOST_DEVICE
126	void
127	copy_if(AutoCopyAsync                const& cpy,
128	        PrdTensor                    const& pred,
129	        Tensor<SrcEngine, SrcLayout> const& src,
130	        Tensor<DstEngine, DstLayout>      & dst)
131	{
132	  using SrcElemWithConst = remove_reference_t<typename SrcEngine::reference>;
133	  using SrcType = typename SrcEngine::value_type;
134	  using DstType = typename DstEngine::value_type;
135	
136	  auto copy_op = []() {
137	#if defined(CUTE_ARCH_CP_ASYNC_SM80_ENABLED)
138	    if constexpr (is_gmem<SrcEngine>::value && is_smem<DstEngine>::value &&
139	                  sizeof(SrcType) == sizeof(DstType)) {
140	      if constexpr (is_const_v<SrcElemWithConst> && sizeof(SrcType) == 16) {
141	          return SM80_CP_ASYNC_CACHEGLOBAL<SrcType,DstType>{};
142	      } else if constexpr (sizeof(SrcType) == 4 || sizeof(SrcType) == 8 || sizeof(SrcType) == 16) {
143	          return SM80_CP_ASYNC_CACHEALWAYS<SrcType,DstType>{};
144	      } else {
145	          return UniversalCopy<SrcType,DstType>{};
146	      }
147	    } else {
148	        return UniversalCopy<SrcType,DstType>{};
149	    }
150	
151	    CUTE_GCC_UNREACHABLE;
152	#else
153	    return UniversalCopy<SrcType,DstType>{};
154	#endif
155	  }();
156	
157	  CUTE_UNROLL
158	  for (int i = 0; i < size(dst); ++i) {
159	    if (pred(i)) {
160	      copy_op.copy(src(i), dst(i));
161	    }
162	  }
163	}
