276	template <class Base>
277	struct AutoFilter {
278	  Base const& base;
279	  CUTE_HOST_DEVICE AutoFilter(Base const& b) : base(b) {}
280	};
281	
282	// Specialization for AutoFilter
283	template <class CopyOp,
284	          class SrcEngine, class SrcLayout,
285	          class DstEngine, class DstLayout>
286	CUTE_HOST_DEVICE
287	void
288	copy(AutoFilter<CopyOp>           const& copy_op,
289	     Tensor<SrcEngine, SrcLayout> const& src,
290	     Tensor<DstEngine, DstLayout>      & dst)
291	{
292	  if constexpr (is_constant<true, decltype(size(src) == size(dst))>::value) {
293	    auto dst_null = nullspace(dst.layout());
294	
295	    Tensor dst_n = zipped_divide(dst, dst_null);
296	    Tensor src_n = zipped_divide(src, dst_null);
297	
298	    CUTE_STATIC_ASSERT_V(cosize<0>(dst_n.layout()) == Int<1>{}, "Nullspace definition error");
299	    CUTE_STATIC_ASSERT_V(cosize<0>(src_n.layout()) == Int<1>{}, "Error: Ambiguous race-condition detected.");
300	
301	    copy(copy_op.base, src_n(Int<0>{},_), dst_n(Int<0>{},_));
302	  } else {
303	    copy(copy_op.base, src, dst);
304	  }
305	}
306	
307	// Auto-vectorizing copy for static layouts
308	template <class SrcEngine, class SrcLayout,
309	          class DstEngine, class DstLayout>
310	CUTE_HOST_DEVICE
311	void
312	copy(Tensor<SrcEngine, SrcLayout> const& src,
313	     Tensor<DstEngine, DstLayout>      & dst)
314	{
315	  if constexpr (is_static<SrcLayout>::value && is_static<DstLayout>::value) {
316	    // Assume Tensors with static layouts (e.g. registers) have pointers that are 128b aligned
317	    return copy(AutoFilter(AutoVectorizingCopyWithAssumedAlignment<128>{}), src, dst);
318	  } else
319	  if constexpr (is_static<decltype(shape(src))>::value && is_static<decltype(shape(dst))>::value) {
320	    // Tensors with static shapes can be filtered, but do not assume that dynamic layouts are aligned.
321	    return copy(AutoFilter(AutoVectorizingCopyWithAssumedAlignment<8>{}), src, dst);
322	  } else {
323	    // Do not assume that dynamic layouts are aligned.
324	    return copy(AutoVectorizingCopyWithAssumedAlignment<8>{}, src, dst);
325	  }
326	}
327	
328	// Auto-vectorizing copy with assumed alignment up to 128bit.
329	template <class SrcEngine, class SrcLayout,
330	          class DstEngine, class DstLayout>
331	CUTE_HOST_DEVICE
332	void
333	copy_aligned(Tensor<SrcEngine, SrcLayout> const& src,
334	             Tensor<DstEngine, DstLayout>      & dst)
335	{
336	  if constexpr (is_static<decltype(shape(src))>::value && is_static<decltype(shape(dst))>::value) {
337	    // Tensors with static shapes can be filtered
338	    return copy(AutoFilter(AutoVectorizingCopyWithAssumedAlignment<128>{}), src, dst);
339	  } else {
340	    return copy(AutoVectorizingCopyWithAssumedAlignment<128>{}, src, dst);
341	  }
342	}
