358	          class SrcEngine, class SrcLayout,
359	          class DstEngine, class DstLayout>
360	CUTE_HOST_DEVICE
361	void
362	copy(Copy_Atom<Copy_Traits<AutoVectorizingCopyWithAssumedAlignment<MaxVecBits>>, Args...> const&,
363	     Tensor<SrcEngine, SrcLayout>                                                         const& src,
