51	void
52	gemm_device(ProblemShape shape_MNK, CtaTiler cta_tiler,
53	            TA const* A, AStride dA, ASmemLayout sA_layout, AThreadLayout tA,
54	            TB const* B, BStride dB, BSmemLayout sB_layout, BThreadLayout tB,
55	            TC      * C, CStride dC, CSmemLayout          , CThreadLayout tC,
56	            Alpha alpha, Beta beta)
57	{
58	  using namespace cute;
59	
60	  // Preconditions
61	  CUTE_STATIC_ASSERT_V(rank(shape_MNK) == Int<3>{});                   // (M, N, K)
62	  CUTE_STATIC_ASSERT_V(rank(cta_tiler) == Int<3>{});                   // (BLK_M, BLK_N, BLK_K)
63	
64	  static_assert(is_static<AThreadLayout>::value);
65	  static_assert(is_static<BThreadLayout>::value);
66	  static_assert(is_static<CThreadLayout>::value);
67	
68	  CUTE_STATIC_ASSERT_V(size(tA) == size(tB));                          // NumThreads
69	  CUTE_STATIC_ASSERT_V(size(tC) == size(tA));                          // NumThreads
70	
71	  CUTE_STATIC_ASSERT_V(size<0>(cta_tiler) % size<0>(tA) == Int<0>{});  // BLK_M / THR_M
72	  CUTE_STATIC_ASSERT_V(size<2>(cta_tiler) % size<1>(tA) == Int<0>{});  // BLK_K / THR_K
73	  CUTE_STATIC_ASSERT_V(size<1>(cta_tiler) % size<0>(tB) == Int<0>{});  // BLK_N / THR_N
74	  CUTE_STATIC_ASSERT_V(size<2>(cta_tiler) % size<1>(tB) == Int<0>{});  // BLK_K / THR_K
75	  CUTE_STATIC_ASSERT_V(size<0>(cta_tiler) % size<0>(tC) == Int<0>{});  // BLK_M / THR_M
76	  CUTE_STATIC_ASSERT_V(size<1>(cta_tiler) % size<1>(tC) == Int<0>{});  // BLK_N / THR_N
77	
78	  static_assert(is_static<ASmemLayout>::value);
79	  static_assert(is_static<BSmemLayout>::value);
80	  static_assert(is_static<CSmemLayout>::value);
81	
82	  CUTE_STATIC_ASSERT_V(size<0>(ASmemLayout{}) == size<0>(cta_tiler));  // BLK_M
83	  CUTE_STATIC_ASSERT_V(size<0>(CSmemLayout{}) == size<0>(cta_tiler));  // BLK_M
84	  CUTE_STATIC_ASSERT_V(size<0>(BSmemLayout{}) == size<1>(cta_tiler));  // BLK_N
85	  CUTE_STATIC_ASSERT_V(size<1>(CSmemLayout{}) == size<1>(cta_tiler));  // BLK_N
86	  CUTE_STATIC_ASSERT_V(size<1>(ASmemLayout{}) == size<2>(cta_tiler));  // BLK_K
87	  CUTE_STATIC_ASSERT_V(size<1>(BSmemLayout{}) == size<2>(cta_tiler));  // BLK_K
88	
89	  CUTE_STATIC_ASSERT_V(congruent(select<0,2>(shape_MNK), dA));         // dA strides for shape MK
90	  CUTE_STATIC_ASSERT_V(congruent(select<1,2>(shape_MNK), dB));         // dB strides for shape NK
91	  CUTE_STATIC_ASSERT_V(congruent(select<0,1>(shape_MNK), dC));         // dC strides for shape MN
92	
93	  //
94	  // Full and Tiled Tensors
95	  //
96	
97	  // Represent the full tensors
98	  Tensor mA = make_tensor(make_gmem_ptr(A), select<0,2>(shape_MNK), dA); // (M,K)
99	  Tensor mB = make_tensor(make_gmem_ptr(B), select<1,2>(shape_MNK), dB); // (N,K)
100	  Tensor mC = make_tensor(make_gmem_ptr(C), select<0,1>(shape_MNK), dC); // (M,N)
101	
102	  // Get the appropriate blocks for this thread block
103	  auto cta_coord = make_coord(blockIdx.x, blockIdx.y, _);              // (m,n,k)
104	  Tensor gA = local_tile(mA, cta_tiler, cta_coord, Step<_1, X,_1>{});  // (BLK_M,BLK_K,k)
105	  Tensor gB = local_tile(mB, cta_tiler, cta_coord, Step< X,_1,_1>{});  // (BLK_N,BLK_K,k)
106	  Tensor gC = local_tile(mC, cta_tiler, cta_coord, Step<_1,_1, X>{});  // (BLK_M,BLK_N)
107	
108	  // Shared memory buffers
109	  __shared__ TA smemA[cosize_v<ASmemLayout>];
110	  __shared__ TB smemB[cosize_v<BSmemLayout>];
111	  Tensor sA = make_tensor(make_smem_ptr(smemA), sA_layout);            // (BLK_M,BLK_K)
112	  Tensor sB = make_tensor(make_smem_ptr(smemB), sB_layout);            // (BLK_N,BLK_K)
113	
114	  //
115	  // Partition the copying of A and B tiles across the threads
116	  //
117	
118	  // TUTORIAL: Example of simple raked partitioning of ThreadLayouts tA|tB over data A|B tiles
119	
120	  Tensor tAgA = local_partition(gA, tA, threadIdx.x);                  // (THR_M,THR_K,k)
121	  Tensor tAsA = local_partition(sA, tA, threadIdx.x);                  // (THR_M,THR_K)
122	
123	  Tensor tBgB = local_partition(gB, tB, threadIdx.x);                  // (THR_N,THR_K,k)
124	  Tensor tBsB = local_partition(sB, tB, threadIdx.x);                  // (THR_N,THR_K)
125	
126	  CUTE_STATIC_ASSERT_V(size<0>(tAgA) == size<0>(tAsA));                // THR_M
127	  CUTE_STATIC_ASSERT_V(size<1>(tAgA) == size<1>(tAsA));                // THR_K
128	  CUTE_STATIC_ASSERT_V(size<0>(tBgB) == size<0>(tBsB));                // THR_N
129	  CUTE_STATIC_ASSERT_V(size<1>(tBgB) == size<1>(tBsB));                // THR_K
130	
131	  //
132	  // Define A/B partitioning and C accumulators
133	  //
134	
135	  // TUTORIAL: Example of partitioning via projections of a ThreadLayout tC
136	
137	  // Partition sA (BLK_M, BLK_K) by the rows of tC
138	  Tensor tCsA = local_partition(sA, tC, threadIdx.x, Step<_1, X>{});   // (THR_M,BLK_K)
139	  // Partition sB (BLK_N, BLK_K) by the cols of tC
140	  Tensor tCsB = local_partition(sB, tC, threadIdx.x, Step< X,_1>{});   // (THR_N,BLK_K)
141	  // Partition gC (M,N) by the tile of tC
142	  Tensor tCgC = local_partition(gC, tC, threadIdx.x, Step<_1,_1>{});   // (THR_M,THR_N)
143	
144	  // Allocate the accumulators -- same shape/layout as the partitioned data
145	  Tensor tCrC = make_tensor_like(tCgC);                                // (THR_M,THR_N)
146	
147	  CUTE_STATIC_ASSERT_V(size<0>(tCrC) == size<0>(tCgC));                // THR_M
148	  CUTE_STATIC_ASSERT_V(size<0>(tCrC) == size<0>(tCsA));                // THR_M
149	  CUTE_STATIC_ASSERT_V(size<1>(tCrC) == size<1>(tCgC));                // THR_N
150	  CUTE_STATIC_ASSERT_V(size<1>(tCrC) == size<0>(tCsB));                // THR_N
151	  CUTE_STATIC_ASSERT_V(size<1>(tCsA) == size<1>(tCsB));                // BLK_K
152	
153	  // Clear the accumulators
154	  clear(tCrC);
155	
156	#if 0
157	  if(thread0()) {
158	    print("  mA : "); print(  mA); print("\n");
159	    print("  gA : "); print(  gA); print("\n");
160	    print("  sA : "); print(  sA); print("\n");
161	    print("tAgA : "); print(tAgA); print("\n");
162	    print("tAsA : "); print(tAsA); print("\n");
163	  }
164	#endif
165	
166	#if 0
167	  if(thread0()) {
168	    print("  mB : "); print(  mB); print("\n");
169	    print("  gB : "); print(  gB); print("\n");
170	    print("  sB : "); print(  sB); print("\n");
171	    print("tBgB : "); print(tBgB); print("\n");
172	    print("tBsB : "); print(tBsB); print("\n");
173	  }
174	#endif
175	
176	#if 0
177	  if(thread0()) {
178	    print("  mC : "); print(  mC); print("\n");
179	    print("  gC : "); print(  gC); print("\n");
180	    print("tCsA : "); print(tCsA); print("\n");
181	    print("tCsB : "); print(tCsB); print("\n");
182	    print("tCgC : "); print(tCgC); print("\n");
183	    print("tCrC : "); print(tCrC); print("\n");
184	  }
185	#endif
186	
187	#if 1
188	
189	  // TUTORIAL: Example of a simple mainloop that read tiles of data into shared memory,
190	  //           and then computes on those tiles.
191	  //   copy(.) operates on the global and shared memory via the tA|tB partitioning
192	  //   gemm(.) operates on the shared and register memory via the tC partitioning
193	
194	  auto K_TILE_MAX = size<2>(tAgA);
195	
196	  for (int k_tile = 0; k_tile < K_TILE_MAX; ++k_tile)
197	  {
198	    // Copy gmem to smem with tA|tB thread-partitioned tensors
199	    copy(tAgA(_,_,k_tile), tAsA);      // A   (THR_M,THR_K) -> (THR_M,THR_K)
200	    copy(tBgB(_,_,k_tile), tBsB);      // B   (THR_N,THR_K) -> (THR_N,THR_K)
201	
202	    // TUTORIAL: The above call to copy(tAgA(_,_,k_tile), tAsA) is equivalent to
203	    //   Tensor tAgAk = tAgA(_,_,k_tile);
204	    //   CUTE_UNROLL
205	    //   for (int i = 0; i < size(tAsA); ++i) {
206	    //     tAsA(i) = tAgAk(i);
207	    //   }
208	
209	    cp_async_fence();        // Label the end of (potential) cp.async instructions
210	    cp_async_wait<0>();      // Sync on all (potential) cp.async instructions
211	    __syncthreads();         // Wait for all threads to write to smem
212	
213	    // Compute gemm on tC thread-partitioned smem
214	    gemm(tCsA, tCsB, tCrC);            // (THR_M,THR_N) += (THR_M,BLK_K) * (THR_N,BLK_K)
215	
216	    // TUTORIAL: The above call to gemm(tCsA, tCsB, tCrC) is equivalent to
217	    //   CUTE_UNROLL
218	    //   for (int k = 0; k < size<1>(tCsA); ++k) {
219	    //     CUTE_UNROLL
220	    //     for (int m = 0; m < size<0>(tCrC); ++m) {
221	    //       CUTE_UNROLL
222	    //       for (int n = 0; n < size<1>(tCrC); ++n) {
223	    //         tCrC(m,n) += tCsA(m,k) * tCsB(n,k);
224	    //       }
225	    //     }
226	    //   }
227	
228	    __syncthreads();         // Wait for all threads to read from smem
229	  }
230	
231	#endif
232	
233	  //
234	  // Epilogue
235	  //
236	
237	  axpby(alpha, tCrC, beta, tCgC);
238	
239	  // TUTORIAL: The above call to axpby(alpha, tCrC, beta, tCgC) is equivalent to
240	  //   CUTE_UNROLL
241	  //   for (int i = 0; i < size(tCrC); ++i) {
242	  //     tCgC(i) = alpha * tCrC(i) + beta * tCgC(i);
243	  //   }
244	}
245	
246	// Setup params for an NT GEMM
247	// Use m-major smem sA, n-major smem sB, and mn-major threads tA|tB
248	template <class TA, class TB, class TC,
249	          class Alpha, class Beta>
250	void
251	gemm_nt(int m, int n, int k,
252	        Alpha alpha,
253	        TA const* A, int ldA,
254	        TB const* B, int ldB,
255	        Beta beta,
256	        TC      * C, int ldC,
257	        cudaStream_t stream = 0)
258	{
259	  using namespace cute;
260	
261	  // Define shapes (dynamic)
262	  auto M = int(m);
263	  auto N = int(n);
264	  auto K = int(k);
265	  auto prob_shape = make_shape(M, N, K);                     // (M, N, K)
266	
267	  // Define NT strides (mixed)
268	  auto dA = make_stride(Int<1>{}, ldA);                      // (dM, dK)
269	  auto dB = make_stride(Int<1>{}, ldB);                      // (dN, dK)
270	  auto dC = make_stride(Int<1>{}, ldC);                      // (dM, dN)
271	
272	  // Define CTA tile sizes (static)
273	  auto bM = Int<128>{};
274	  auto bN = Int<128>{};
275	  auto bK = Int<  8>{};
276	  auto cta_tiler = make_shape(bM, bN, bK);                   // (BLK_M, BLK_N, BLK_K)
277	
278	  // Define the smem layouts (static)
279	  auto sA = make_layout(make_shape(bM, bK));                 // (m,k) -> smem_idx; m-major
280	  auto sB = make_layout(make_shape(bN, bK));                 // (n,k) -> smem_idx; n-major
281	  auto sC = make_layout(make_shape(bM, bN));                 // (m,n) -> smem_idx; m-major
282	
283	  // Define the thread layouts (static)
284	  auto tA = make_layout(make_shape(Int<32>{}, Int< 8>{}));   // (m,k) -> thr_idx
285	  auto tB = make_layout(make_shape(Int<32>{}, Int< 8>{}));   // (n,k) -> thr_idx
286	  auto tC = make_layout(make_shape(Int<16>{}, Int<16>{}));   // (m,n) -> thr_idx
287	
288	  dim3 dimBlock(size(tC));
289	  dim3 dimGrid(size(ceil_div(M, bM)),
290	               size(ceil_div(N, bN)));
291	  gemm_device<<<dimGrid, dimBlock, 0, stream>>>
292	      (prob_shape, cta_tiler,
293	       A, dA, sA, tA,
294	       B, dB, sB, tB,
295	       C, dC, sC, tC,
296	       alpha, beta);
297	}
298	
299	// Setup params for a TN GEMM
300	// Use padded m-major smem sA, padded n-major smem sB, and k-major threads tA|tB
301	template <class TA, class TB, class TC,
302	          class Alpha, class Beta>
303	void
304	gemm_tn(int m, int n, int k,
305	        Alpha alpha,
306	        TA const* A, int ldA,
307	        TB const* B, int ldB,
308	        Beta beta,
309	        TC      * C, int ldC,
310	        cudaStream_t stream = 0)
311	{
312	  using namespace cute;
313	
314	  // Define shapes (dynamic)
315	  auto M = int(m);
316	  auto N = int(n);
317	  auto K = int(k);
318	  auto prob_shape = make_shape(M, N, K);                     // (M, N, K)
319	
320	  // Define TN strides (mixed)
321	  auto dA = make_stride(ldA, Int<1>{});                      // (dM, dK)
322	  auto dB = make_stride(ldB, Int<1>{});                      // (dN, dK)
323	  auto dC = make_stride(Int<1>{}, ldC);                      // (dM, dN)
324	
325	  // Define CTA tile sizes (static)
326	  auto bM = Int<128>{};
327	  auto bN = Int<128>{};
328	  auto bK = Int<  8>{};
329	  auto cta_tiler = make_shape(bM, bN, bK);                   // (BLK_M, BLK_N, BLK_K)
330	
331	  // Define the smem layouts (static)
332	  auto sA = make_layout(make_shape(bM,bK), LayoutRight{});   // (m,k) -> smem_idx; k-major
333	  auto sB = make_layout(make_shape(bN,bK), LayoutRight{});   // (n,k) -> smem_idx; k-major
334	  auto sC = make_layout(make_shape(bM, bN));                 // (m,n) -> smem_idx; m-major
335	
336	  // Define the thread layouts (static)
337	  auto tA = make_layout(make_shape(Int<32>{}, Int< 8>{}), LayoutRight{});  // (m,k) -> thr_idx; k-major
338	  auto tB = make_layout(make_shape(Int<32>{}, Int< 8>{}), LayoutRight{});  // (n,k) -> thr_idx; k-major
339	  auto tC = make_layout(make_shape(Int<16>{}, Int<16>{}));                 // (m,n) -> thr_idx; m-major
340	
341	  dim3 dimBlock(size(tC));
342	  dim3 dimGrid(size(ceil_div(M, bM)),
343	               size(ceil_div(N, bN)));
344	  gemm_device<<<dimGrid, dimBlock, 0, stream>>>
345	      (prob_shape, cta_tiler,
346	       A, dA, sA, tA,
347	       B, dB, sB, tB,
348	       C, dC, sC, tC,
349	       alpha, beta);
350	}
351	
352	template <class TA, class TB, class TC,
353	          class Alpha, class Beta>
354	void
355	gemm(char transA, char transB, int m, int n, int k,
356	     Alpha alpha,
357	     TA const* A, int ldA,
358	     TB const* B, int ldB,
359	     Beta beta,
360	     TC      * C, int ldC,
361	     cudaStream_t stream = 0)
362	{
363	  if (transA == 'N' && transB == 'T') {
364	    return gemm_nt(m, n, k, alpha, A, ldA, B, ldB, beta, C, ldC, stream);
365	  } else
366	  if (transA == 'T' && transB == 'N') {
367	    return gemm_tn(m, n, k, alpha, A, ldA, B, ldB, beta, C, ldC, stream);
368	  }
369	  assert(false && "Not implemented");
370	}
371	
372	
373	int main(int argc, char** argv)
374	{
375	  int m = 5120;
376	  if (argc >= 2)
377	    sscanf(argv[1], "%d", &m);
378	
379	  int n = 5120;
380	  if (argc >= 3)
381	    sscanf(argv[2], "%d", &n);
382	
383	  int k = 4096;
384	  if (argc >= 4)
385	    sscanf(argv[3], "%d", &k);
386	
387	  char transA = 'N';
388	  if (argc >= 5)
389	    sscanf(argv[4], "%c", &transA);
390	
391	  char transB = 'T';
392	  if (argc >= 6)
393	    sscanf(argv[5], "%c", &transB);
394	
395	  using TA = float;
396	  using TB = float;
397	  using TC = float;
398	  using TI = float;
399	
400	  TI alpha = 1.0;
401	  TI beta  = 0.0;
402	
403	  std::cout << "M = " << m << std::endl;
404	  std::cout << "N = " << n << std::endl;
405	  std::cout << "K = " << k << std::endl;
406	  std::cout << "C = A^" << transA << " B^" << transB << std::endl;
407	
408	  cute::device_init(0);
409	
410	  thrust::host_vector<TA> h_A(m*k);
411	  thrust::host_vector<TB> h_B(n*k);
412	  thrust::host_vector<TC> h_C(m*n);
413	
414	  for (int j = 0; j < m*k; ++j) h_A[j] = static_cast<TA>( 2*(rand() / double(RAND_MAX)) - 1 );
415	  for (int j = 0; j < n*k; ++j) h_B[j] = static_cast<TB>( 2*(rand() / double(RAND_MAX)) - 1 );
416	  for (int j = 0; j < m*n; ++j) h_C[j] = static_cast<TC>(-1);
417	
418	  thrust::device_vector<TA> d_A = h_A;
419	  thrust::device_vector<TB> d_B = h_B;
420	  thrust::device_vector<TC> d_C = h_C;
421	
422	  double gflops = (2.0*m*n*k) * 1e-9;
423	
424	  const int timing_iterations = 100;
425	  GPU_Clock timer;
426	
427	  int ldA = 0, ldB = 0, ldC = m;
428	
429	  if (transA == 'N') {
430	    ldA = m;
431	  } else if (transA == 'T') {
432	    ldA = k;
433	  } else {
434	    assert(false);
435	  }
436	
437	  if (transB == 'N') {
438	    ldB = k;
439	  } else if (transB == 'T') {
440	    ldB = n;
441	  } else {
442	    assert(false);
443	  }
444	  // Run once
445	  d_C = h_C;
446	  gemm(transA, transB, m, n, k,
447	       alpha,
448	       d_A.data().get(), ldA,
449	       d_B.data().get(), ldB,
450	       beta,
451	       d_C.data().get(), ldC);
452	  CUTE_CHECK_LAST();
453	  thrust::host_vector<TC> cute_result = d_C;
454	
455	  // Timing iterations
456	  timer.start();
457	  for (int i = 0; i < timing_iterations; ++i) {
458	    gemm(transA, transB, m, n, k,
459	         alpha,
460	         d_A.data().get(), ldA,
461	         d_B.data().get(), ldB,
462	         beta,
463	         d_C.data().get(), ldC);
464	  }
465	  double cute_time = timer.seconds() / timing_iterations;
466	  CUTE_CHECK_LAST();
467	  printf("CUTE_GEMM:     [%6.1f]GFlop/s  (%6.4f)ms\n", gflops / cute_time, cute_time*1000);
468	  return 0;
469	}
